sparql:
SELECT(COUNT(?richmond_year) AS ?count) WHERE {
  {
    SELECT(MIN(?collingwood_year) AS ?collingwood_year) WHERE {
      wd:Q249679 wdt:P1936 ?season .
      ?season wdt:P118 wd:Q521525 .
      ?season wdt:P585 ?collingwood_year .
    }
  }
  wd:Q2521385 wdt:P1936 ?richmond_season .
  ?richmond_season wdt:P118 wd:Q521525 .
  ?richmond_season wdt:P585 ?richmond_year .
  FILTER(?richmond_year > ?collingwood_year)
}

SELECT ?fitzroyYear ?latestYear (?latestYear - ?fitzroyYear AS ?yearsDifference)
WHERE {
  # Fitzroy's first premiership year (min year)
  {
    SELECT ?fitzroyYear
    WHERE {
      wd:Q200493 p:P1296 ?statement.
      ?statement ps:P1296 wd:Q3044572.
      ?statement pq:P585 ?year.
      FILTER (datatype(?year) = xsd:gYear)
    }
    ORDER BY ASC(?year)
    LIMIT 1
  }
  # Collingwood's latest premiership year
  {
    SELECT ?collingwoodYear
    WHERE {
      wd:Q200493 p:P1296 ?statement.
      ?statement ps:P1296 wd:Q176729.
      ?statement pq:P585 ?year.
      FILTER (datatype(?year) = xsd:gYear)
    }
    ORDER BY DESC(?year)
    LIMIT 1
  }
  # Richmond's latest premiership year
  {
    SELECT ?richmondYear
    WHERE {
      wd:Q200493 p:P1296 ?statement.
      ?statement ps:P1296 wd:Q142232.
      ?statement pq:P585 ?year.
      FILTER (datatype(?year) = xsd:gYear)
    }
    ORDER BY DESC(?year)
    LIMIT 1
  }
  # Compute the max of Collingwood and Richmond's years
  BIND(MAX(?collingwoodYear, ?richmondYear) AS ?latestYear)
}
LIMIT 1

SELECT (MAX(?year) - MIN(?year)) AS ?difference
WHERE {
  ?edition wdt:P31 wd:Q1363275;
          wdt:P1923 wd:Q334634, wd:Q650840;
          wdt:P577 ?date.
  BIND(YEAR(?date) AS ?year)
}
